from typing import List
from collections import defaultdict

class Solution:
    def medianOfUniquenessArray(self, nums: List[int]) -> int:
        n = len(nums)
        total_subarrays = n * (n + 1) // 2

        # Function to count number of subarrays with at most k distinct elements
        def count_subarrays_with_at_most_k_distinct(k):
            freq = defaultdict(int)
            left = 0
            count = 0
            for right in range(n):
                freq[nums[right]] += 1
                while len(freq) > k:
                    freq[nums[left]] -= 1
                    if freq[nums[left]] == 0:
                        del freq[nums[left]]
                    left += 1
                count += right - left + 1
            return count

        # Binary search for the median
        low, high = 1, n
        while low < high:
            mid = (low + high) // 2
            if count_subarrays_with_at_most_k_distinct(mid) < (total_subarrays + 1) // 2:
                low = mid + 1
            else:
                high = mid

        return low
